const input = $input.first().json;
const body = input.body || {};

// Verify token
if (!body.token) {
  return [{ json: { error: 'Token is required', statusCode: 401, valid: false } }];
}

try {
  const parts = body.token.split('.');
  if (parts.length !== 3) {
    return [{ json: { error: 'Invalid token format', statusCode: 401, valid: false } }];
  }

  let payload = parts[1].replace(/-/g, '+').replace(/_/g, '/');
  while (payload.length % 4) payload += '=';
  const decoded = JSON.parse(Buffer.from(payload, 'base64').toString('utf8'));

  if (!decoded.user_id) {
    return [{ json: { error: 'Invalid token: missing user_id', statusCode: 401, valid: false } }];
  }

  if (decoded.exp && decoded.exp < Math.floor(Date.now() / 1000)) {
    return [{ json: { error: 'Token expired', statusCode: 401, valid: false } }];
  }

  // Validate required fields
  if (!body.name || !body.name.trim()) {
    return [{ json: { error: 'Vendor name is required', statusCode: 400, valid: false } }];
  }

  const validSources = ['shopify', 'woocommerce', 'prestashop', 'api', 'excel'];
  if (!body.source || !validSources.includes(body.source)) {
    return [{ json: { error: `Source must be one of: ${validSources.join(', ')}`, statusCode: 400, valid: false } }];
  }

  // Build vendor data
  const vendorData = {
    user_id: decoded.user_id,
    name: body.name.trim(),
    company: (body.company || '').trim() || null,
    source: body.source,
    source_url: (body.source_url || '').trim() || null,
    source_api_key: (body.source_api_key || '').trim() || null,
    source_api_secret: (body.source_api_secret || '').trim() || null,
    marketplace_id: (body.marketplace_id || '').trim() || null,
    marketplace_api_key: (body.marketplace_api_key || '').trim() || null,
    marketplace_url: (body.marketplace_url || '').trim() || null,
    sync_interval_hours: parseInt(body.sync_interval_hours) || 24,
    sync_status: 'pending',
    config: body.config || {}
  };

  return [{ json: { valid: true, user_id: decoded.user_id, vendorData, source: body.source, source_url: body.source_url, source_api_key: body.source_api_key, source_api_secret: body.source_api_secret } }];
} catch (e) {
  return [{ json: { error: 'Token decode failed: ' + e.message, statusCode: 401, valid: false } }];
}

const created = $input.first().json;
const vendor = Array.isArray(created) ? created[0] : created;

// Get original input data
const inputData = $('Verify Token & Validate').first().json;
const source = inputData.source;
const sourceUrl = inputData.source_url;
const apiKey = inputData.source_api_key;
const apiSecret = inputData.source_api_secret;

// Determine if we should test connection
const shouldTest = sourceUrl && apiKey && ['shopify', 'woocommerce'].includes(source);

return [{ json: { vendor, source, sourceUrl, apiKey, apiSecret, shouldTest } }];

const { vendor, source, sourceUrl, apiKey, apiSecret } = $input.first().json;

let connectionTest = 'skipped';
let testError = null;

try {
  let url, headers;

  if (source === 'shopify') {
    // Clean URL: ensure no trailing slash
    const cleanUrl = sourceUrl.replace(/\/+$/, '');
    url = `${cleanUrl}/admin/api/2024-01/shop.json`;
    headers = { 'X-Shopify-Access-Token': apiKey };
  } else if (source === 'woocommerce') {
    const cleanUrl = sourceUrl.replace(/\/+$/, '');
    url = `${cleanUrl}/wp-json/wc/v3/system_status`;
    const basicAuth = Buffer.from(`${apiKey}:${apiSecret}`).toString('base64');
    headers = { 'Authorization': `Basic ${basicAuth}` };
  }

  if (url) {
    const response = await fetch(url, {
      method: 'GET',
      headers,
      signal: AbortSignal.timeout(10000)
    });

    if (response.ok) {
      connectionTest = 'ok';
    } else {
      connectionTest = 'failed';
      testError = `HTTP ${response.status}: ${response.statusText}`;
    }
  }
} catch (e) {
  connectionTest = 'failed';
  testError = e.message;
}

// Update sync_status based on test result
const syncStatus = connectionTest === 'ok' ? 'active' : 'pending';

return [{ json: { vendor, connectionTest, testError, syncStatus, updateStatus: true } }];

// This node receives from either the PATCH result or the skip path
let vendor, connectionTest, testError;

try {
  // Try to get data from the Update Status node's input
  const prev = $input.first().json;

  // If we came from the PATCH, get the updated vendor
  if (Array.isArray(prev)) {
    vendor = prev[0];
    const testData = $('Test Source Connection').first().json;
    connectionTest = testData.connectionTest;
    testError = testData.testError;
  } else if (prev.vendor) {
    vendor = prev.vendor;
    connectionTest = prev.connectionTest;
    testError = prev.testError;
  } else {
    // Came from PATCH HTTP response
    vendor = prev;
    const testData = $('Test Source Connection').first().json;
    connectionTest = testData.connectionTest;
    testError = testData.testError;
  }
} catch (e) {
  // Fallback: came from skip path
  const skipData = $('Skip Test Response').first().json;
  vendor = skipData.vendor;
  connectionTest = skipData.connectionTest;
  testError = skipData.testError;
}

const response = {
  success: true,
  vendor,
  connection_test: connectionTest
};

if (testError) {
  response.connection_error = testError;
}

return [{ json: response }];
